import 'package:firebase_auth/firebase_auth.dart'; import 'package:flutter/material.dart'; import '../services/ai_agent_service.dart';
class AIAgentScreen extends StatefulWidget { const AIAgentScreen({super.key}); @override State<AIAgentScreen> createState()=>_AIAgentScreenState(); }
class _AIAgentScreenState extends State<AIAgentScreen>{ final agentService=AIAgentService(); final messageController=TextEditingController(); final List<Map<String,String>> messages=[{'sender':'ai','text':'Hi, I am your AI Campus Agent. I can help with reminders, resources, timetable, announcements, events, and campus navigation only.'}]; bool isLoading=false;
Future<void> sendMessage() async { final text=messageController.text.trim(); if(text.isEmpty) return; setState((){messages.add({'sender':'user','text':text}); isLoading=true; messageController.clear();}); final response=await agentService.handleMessage(userId: FirebaseAuth.instance.currentUser?.uid??'', message:text); if(!mounted) return; setState((){messages.add({'sender':'ai','text':response}); isLoading=false;}); }
Widget bubble(Map<String,String> m){ final isUser=m['sender']=='user'; return Align(alignment: isUser?Alignment.centerRight:Alignment.centerLeft, child: Container(margin: const EdgeInsets.only(bottom:10), padding: const EdgeInsets.all(12), constraints: const BoxConstraints(maxWidth:320), decoration: BoxDecoration(color: isUser?Colors.blue:Colors.white, borderRadius: BorderRadius.circular(14), boxShadow: const [BoxShadow(color:Colors.black12, blurRadius:3)]), child: Text(m['text']??'', style: TextStyle(color: isUser?Colors.white:Colors.black87)))); }
@override void dispose(){messageController.dispose(); super.dispose();}
@override Widget build(BuildContext context){ final examples=['Remind me Friday 9am ITM3206 test','Find ITM3206 course outline','Where is Finance Office?','Show latest announcements','What events are available?','Show my timetable']; return Scaffold(appBar: AppBar(title: const Text('AI Campus Agent')), body: Column(children:[ SizedBox(height:52, child: ListView.builder(padding: const EdgeInsets.symmetric(horizontal:12, vertical:8), scrollDirection: Axis.horizontal, itemCount: examples.length, itemBuilder:(context,index)=>Padding(padding: const EdgeInsets.only(right:8), child: ActionChip(label: Text(examples[index]), onPressed:()=>messageController.text=examples[index])))), Expanded(child: ListView.builder(padding: const EdgeInsets.all(16), itemCount: messages.length, itemBuilder:(context,index)=>bubble(messages[index]))), if(isLoading) const LinearProgressIndicator(), SafeArea(child: Padding(padding: const EdgeInsets.all(12), child: Row(children:[Expanded(child: TextField(controller:messageController, decoration: const InputDecoration(hintText:'Ask campus-related question...', border: OutlineInputBorder()), onSubmitted:(_)=>sendMessage())), const SizedBox(width:8), IconButton.filled(onPressed: isLoading?null:sendMessage, icon: const Icon(Icons.send))])))])); }}
